import { createContextNative, destroyContextNative, backendIdNative, maxChannelCountNative } from "./native/audio.bind.js";

export function createContext(name, backendName) {
  return createContextNative(name, backendName);
}

export function destroyContext(context) {
  return destroyContextNative(context);
}

export function backendId(context) {
  return backendIdNative(context);
}

export function maxChannelCount(context) {
  return maxChannelCountNative(context);
}
